INSERT INTO oretir_site_settings (setting_key, value_en, value_es, updated_at) VALUES
('email_tpl_subscriber_welcome_subject', 'Welcome to Oregon Tires! Here''s Your Free Inspection Coupon', 'Bienvenido a Oregon Tires! Aquí está su cupón de inspección gratuita', NOW()),
('email_tpl_subscriber_welcome_greeting', 'Welcome to Oregon Tires Auto Care!', '¡Bienvenido a Oregon Tires Auto Care!', NOW()),
('email_tpl_subscriber_welcome_body', 'Thank you for subscribing to our newsletter! As a thank you, here''s your exclusive coupon for a FREE 21-point vehicle inspection:\n\nUse code: FREEINSPECT\n\nThis inspection covers brakes, tires, fluids, belts, battery, and more. Just mention this code when you book your appointment or show this email at drop-off.\n\nAs a subscriber, you''ll also get:\n• Early access to seasonal tire deals\n• Maintenance reminders and tips\n• Exclusive subscriber-only discounts', 'Gracias por suscribirse a nuestro boletín. Como agradecimiento, aquí tiene su cupón exclusivo para una inspección vehicular GRATUITA de 21 puntos:\n\nUse el código: FREEINSPECT\n\nEsta inspección cubre frenos, llantas, fluidos, correas, batería y más. Solo mencione este código al reservar su cita o muestre este correo al dejar su vehículo.\n\nComo suscriptor, también recibirá:\n• Acceso anticipado a ofertas de llantas de temporada\n• Recordatorios y consejos de mantenimiento\n• Descuentos exclusivos para suscriptores', NOW()),
('email_tpl_subscriber_welcome_button', 'Book Your Free Inspection', 'Reserve su inspección gratuita', NOW()),
('email_tpl_subscriber_welcome_footer', 'Oregon Tires Auto Care | 8536 SE 82nd Ave, Portland, OR 97266 | (503) 367-9714', 'Oregon Tires Auto Care | 8536 SE 82nd Ave, Portland, OR 97266 | (503) 367-9714', NOW())
